oxy_webhelp_navlinks = {"gcalendar_recover_data-d30753e36766":{"topics":[{"title":"Google Calendar recovery scopes","shortdesc":"<p class=\"shortdesc\">Recovery scopes determine the calendar data that can be restored, such as specific calendars and events, or all         calendars of a user.<\/p>","href":"gws\/gcalendar_recovery_scopes.html","attributes":{"data-id":"gcalendar_recovery_scopes"},"menu":{"hasChildren":false},"tocID":"gcalendar_recovery_scopes-d30753e36779","topics":[]},{"title":"Restoring specific events from Google Calendar","shortdesc":"<p class=\"shortdesc\">Use a snapshot to find and restore individual events to the Google Calendar of a         user. You can browse or search calendars and events and use advanced filters to locate         specific events.<\/p>","href":"gws\/gcalendar_restoring_events.html","attributes":{"data-id":"gcalendar_restoring_events"},"menu":{"hasChildren":false},"tocID":"gcalendar_restoring_events-d30753e36790","topics":[]},{"title":"Restoring a full Google Calendar","shortdesc":"<p class=\"shortdesc\">Restore all events in a Google Calendar from a point-in-time snapshot to the original         or a different user account.<\/p>","href":"gws\/gcalendar_restoring_full_calendar.html","attributes":{"data-id":"gcalendar_restoring_full_calendar"},"menu":{"hasChildren":false},"tocID":"gcalendar_restoring_full_calendar-d30753e36801","topics":[]},{"title":"Changing a snapshot for Google Calendar","shortdesc":"<p class=\"shortdesc\">Change to a different point-in-time snapshot to view and restore Google Calendar         data.<\/p>","href":"gws\/gcalendar_changing_snapshot.html","attributes":{"data-id":"gcalendar_changing_snapshot"},"menu":{"hasChildren":false},"tocID":"gcalendar_changing_snapshot-d30753e36812","topics":[]}]}};